export function isFullwidth(char: string): boolean {
  const cp = char.codePointAt(0);
  if (cp === undefined) return false;
  let lo = 0;
  let hi = (R.length >>> 1) - 1;
  while (lo <= hi) {
    const mid = (lo + hi) >>> 1;
    const i = mid << 1;
    if (cp < R[i]) hi = mid - 1;
    else if (cp > R[i + 1]) lo = mid + 1;
    else return true;
  }
  return false;
}
